import React from "react";

const Aboutme = () => {

    return (
        <div className="about-wrapper">
            <header className="about-header">
                About Me
            </header>
            <div className="my-image">
                <img src='src/assets/img/Profile 1.jpg'
                alt="my-picture"></img> 
            </div>
        </div>
    )
};

export default Aboutme;
